var e=[{id:`L2_1`,type:`narration`,speaker:null,text:{KOREA:`더 강하게.`,JPN:`より強く。`,ENG:`To become stronger.`,TWN:`更堅定地。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`narration`,speaker:null,text:{KOREA:`더 빠르게.`,JPN:`より早く。`,ENG:`Faster.`,TWN:`更迅速地。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`narration`,speaker:null,text:{KOREA:`두려워하지 말고… 앞으로 나아가.`,JPN:`恐れずに……前に進んで。`,ENG:`Don't be afraid... just keep moving on.`,TWN:`無所畏懼地……往前走。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`narration`,speaker:null,text:{KOREA:`기억해라, 유미나.`,JPN:`覚えておいて、ヤナギ・ミナ。`,ENG:`Remember, Yoo Mina.`,TWN:`你記住了，劉米娜。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`narration`,speaker:null,text:{KOREA:`네가, 아니. 너야말로…`,JPN:`私が、いや、あなたこそが……`,ENG:`You are, no. Only you are...`,TWN:`你是，不，你才是……`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L7_1`,type:`narration`,speaker:null,text:{KOREA:`우리 늑대 무리의 선두다.`,JPN:`私たち狼の群れの先頭よ。`,ENG:`The leader of our Wolf pack.`,TWN:`我們狼群的領頭狼。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L15_1`,type:`dialog`,speaker:`SAVIOR_KNIGHT_NULL_NULL`,text:{KOREA:`어째서…?`,JPN:`どうして……？`,ENG:`Why...?`,TWN:`為什麼……？`},stage:{bg:`THRONE_VOID`,slots:{L:null,C:{char_id:`SAVIOR_KNIGHT_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`SAVIOR_KNIGHT_NULL_NULL`,text:{KOREA:`어째서!`,JPN:`どうしてだ！`,ENG:`Why?!`,TWN:`為什麼！`},stage:{bg:`THRONE_VOID`,slots:{L:null,C:{char_id:`SAVIOR_KNIGHT_NULL_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`SAVIOR_KNIGHT_NULL_NULL`,text:{KOREA:`어째서 쓰러지지 않는 거지?!`,JPN:`どうして倒れない！？`,ENG:`Why won't you fall down?!`,TWN:`為什麼不倒下呢？！`},stage:{bg:`THRONE_VOID`,slots:{L:null,C:{char_id:`SAVIOR_KNIGHT_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`SAVIOR_KNIGHT_NULL_NULL`,text:{KOREA:`보폭도, 공방의 호흡도, 전부! 내가 장악하고 있는데……!`,JPN:`間合いも、攻防の呼吸も、すべて！　僕が支配しているのに……！`,ENG:`Every step, every attack, everything! I've overpowered you...!`,TWN:`步伐、攻防的節奏，全都！是我在掌控之中……！`},stage:{bg:`THRONE_VOID`,slots:{L:null,C:{char_id:`SAVIOR_KNIGHT_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`SAVIOR_KNIGHT_NULL_NULL`,text:{KOREA:`어째서!`,JPN:`どうしてだ！`,ENG:`Why?!`,TWN:`為什麼！`},stage:{bg:`THRONE_VOID`,slots:{L:null,C:{char_id:`SAVIOR_KNIGHT_NULL_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L25_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NEXT_NULL`,text:{KOREA:`더 이상 멈추지 않아!`,JPN:`もう止まらない！`,ENG:`I won't stop anymore!`,TWN:`我不會再停下！`},stage:{bg:`THRONE_VOID`,slots:{L:null,C:{char_id:`YOOMINA_FENRIR_NEXT_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L26_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NEXT_NULL`,text:{KOREA:`망설이지 않아!`,JPN:`迷わない！`,ENG:`I won't hesitate!`,TWN:`不會再猶豫！`},stage:{bg:`THRONE_VOID`,slots:{L:null,C:{char_id:`YOOMINA_FENRIR_NEXT_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L27_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NEXT_NULL`,text:{KOREA:`선배가 어떤 운명을 짊어지고 있든…`,JPN:`先輩がどんな運命を背負っていようと……`,ENG:`Whatever your fate holds...`,TWN:`不管前輩背負著怎樣的命運……`},stage:{bg:`THRONE_VOID`,slots:{L:null,C:{char_id:`YOOMINA_FENRIR_NEXT_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L28_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NEXT_NULL`,text:{KOREA:`내가 같이 버텨줄게!`,JPN:`私が一緒に耐えてみせる！`,ENG:`I will stand with you!`,TWN:`我都會和你一起堅持下去！`},stage:{bg:`THRONE_VOID`,slots:{L:null,C:{char_id:`YOOMINA_FENRIR_NEXT_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L29_1`,type:`dialog`,speaker:`SAVIOR_KNIGHT_NULL_NULL`,text:{KOREA:`…….`,JPN:`……`,ENG:`...`,TWN:`……`},stage:{bg:`THRONE_VOID`,slots:{L:null,C:{char_id:`SAVIOR_KNIGHT_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L30_1`,type:`dialog`,speaker:`SAVIOR_KNIGHT_NULL_NULL`,text:{KOREA:`정말입니까?`,JPN:`本当なんですか？`,ENG:`Really?`,TWN:`真的嗎？`},stage:{bg:`THRONE_VOID`,slots:{L:null,C:{char_id:`SAVIOR_KNIGHT_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};